  "journal": "Diabetology & metabolic syndrome",
  "doi": "10.1186/s13098-026-02233-w",
  "pmid": "42399973",
  "url": "https://pubmed.ncbi.nlm.nih.gov/42399973/",
  "pubdate": "2026-07-03",
