  "journal": "JPEN. Journal of parenteral and enteral nutrition",
  "doi": "10.1002/jpen.70120",
  "pmid": "42400337",
  "url": "https://pubmed.ncbi.nlm.nih.gov/42400337/",
  "pubdate": "2026-07-04",
